637	          case 'even': {
638	            const taxPerPerson = taxAmount.div(
639	              new Decimal(personItemTotals.size)
640	            );
641	
642	            for (const [personIdentifier, itemTotal] of personItemTotals) {
643	              personItemTotals.set(
644	                personIdentifier,
645	                itemTotal.add(taxPerPerson)
646	              );
647	            }
648	
649	            break;
650	          }
651	
652	          case 'proportional': {
653	            for (const [personIdentifier, itemTotal] of personItemTotals) {
654	              const personSplitTotal = pretax.getPersonSplitTotal(
655	                personIdentifier,
656	                itemSplits
657	              );
658	
659	              const burden = personSplitTotal.div(totalAssignedItemsValue);
660	              const personTaxAmount = taxAmount.mul(burden);
661	
