735	    /**
736	     * Calculates "fair" totals with proper rounding and penny distribution to ensure the sum equals the receipt total.
737	     *
738	     * This function addresses the rounding problem: when individual person totals are rounded to 2 decimal places,
739	     * their sum may not equal the original receipt total. This function distributes rounding differences (pennies)
740	     * fairly among people.
741	     *
742	     * **Algorithm:**
743	     * 1. Converts all amounts to integer cents (truncates to avoid double-conversion errors)
744	     * 2. Calculates the rounding gap between the rounded sum and the receipt total
745	     * 3. Sorts people by largest fractional part (those with the most "leftover" cents get priority)
746	     * 4. Distributes extra/missing pennies one at a time, cycling through people
747	     * 5. Converts back to dollars (Decimal instances)
748	     *
749	     * Uses Decimal.js throughout to maintain precision during the rounding and distribution process.
750	     *
751	     * @param receiptTotal - The total receipt amount as a Decimal instance
752	     * @param personTotals - Map of person identifiers to their calculated totals (as Decimal instances)
753	     * @returns A Map where keys are person identifiers and values are "fair" totals as Decimal instances.
754	     *          The sum of these fair totals equals the receipt total (within 1 cent).
755	     *
756	     * @example
757	     * ```ts
758	     * // Receipt total: $31.00
759	     * // Person totals: [10.333, 10.333, 10.334] (sum = 31.00)
760	     * // After rounding: [10.33, 10.33, 10.34] (sum = 31.00) ✓
761	     *
762	     * const receiptTotal = new Decimal(31.00);
763	     * const personTotals = new Map([
764	     *   [1, new Decimal(10.333)],
765	     *   [2, new Decimal(10.333)],
766	     *   [3, new Decimal(10.334)]
767	     * ]);
768	     * const fairTotals = calculations.final.getPersonFairTotals(receiptTotal, personTotals);
769	     * // Returns: Map([
770	     * //   [1, new Decimal(10.33)],
771	     * //   [2, new Decimal(10.33)],
772	     * //   [3, new Decimal(10.34)]
773	     * // ])
774	     * // Sum: 10.33 + 10.33 + 10.34 = 31.00 ✓
775	     *
776	     * // Example with rounding gap
777	     * // Receipt total: $10.00
778	     * // Person totals: [3.333, 3.333, 3.334] (sum = 10.00)
779	     * // After rounding: [3.33, 3.33, 3.33] (sum = 9.99) - gap of 1 cent
780	     * // Fair totals: [3.33, 3.33, 3.34] (sum = 10.00) - penny goes to person with largest fractional part
781	     * ```
782	     */
783	    export function getPersonFairTotals(
784	      receiptTotal: Decimal,
785	      personTotals: Map<PersonIdentifier, Decimal>
786	    ): Map<PersonIdentifier, Decimal> {
787	      // Step 1: Convert to cents (truncate directly to avoid double-conversion errors)
788	      const inCents = Array.from(personTotals).map(([userId, value]) => ({
789	        userId,
790	        original: value,
791	        cents: new Decimal(value).mul(100).trunc(), // Convert directly to integer cents
792	      }));
793	
794	      // Step 2: Calculate rounding gap in cents
795	      const roundedSumCents = inCents.length
796	        ? Decimal.sum(...inCents.map(({ cents }) => cents))
797	        : new Decimal(0);
798	      const receiptTotalCents = receiptTotal.mul(100).trunc();
799	      let diffCents = receiptTotalCents.minus(roundedSumCents);
800	
801	      // Step 3: Sort by largest fractional part (for fair distribution of pennies)
802	      inCents.sort((a, b) => b.original.mod(1).cmp(a.original.mod(1)));
803	
804	      // Step 4: Distribute the extra pennies by working with integer cents
805	      if (inCents.length > 0) {
806	        let index = 0;
807	        while (!diffCents.isZero()) {
808	          const entry = inCents[index % inCents.length];
809	          entry.cents = entry.cents.plus(diffCents.gt(0) ? 1 : -1); // Add or subtract 1 cent (integer arithmetic)
810	          diffCents = diffCents.plus(diffCents.gt(0) ? -1 : 1);
811	          index++;
812	        }
813	      }
814	
815	      // Step 5: Convert back to dollars and return
816	      const result: Map<PersonIdentifier, Decimal> = new Map(
817	        inCents.map(({ userId, cents }) => [userId, cents.div(100)])
818	      );
819	
820	      return result;
821	    }
822	  }
