import Decimal from 'decimal.js';

import type { ReceiptLineItem } from './ReceiptLineItem';

/**
 * Represents a receipt with all its associated data.
 *
 * Receipts are immutable and created from server state. They contain
 * comprehensive information about a transaction including merchant details,
 * pricing breakdowns, payment information, and line items. All monetary
 * values use Decimal.js for precision to avoid floating-point errors.
 * Use mutation functions to update receipts rather than modifying them directly.
 *
 * @example
 * ```typescript
 * const receipt: Receipt = {
 *   id: 1,
 *   createdAt: new Date("2024-01-15"),
 *   imagePath: "/images/receipt-1.jpg",
 *   imageVisibility: "public",
 *   authUserId: "user-123",
 *   merchant: "Coffee Shop",
 *   date: new Date("2024-01-15"),
 *   paymentMethod: "Credit Card",
 *   subtotal: new Decimal(50.00),
 *   displaySubtotal: new Decimal(50.00),
 *   tax: new Decimal(4.50),
 *   tip: new Decimal(5.00),
 *   gratuity: null,
 *   total: new Decimal(59.50),
 *   itemsTotal: new Decimal(50.00),
 *   pretaxTotal: new Decimal(50.00),
 *   posttaxTotal: new Decimal(54.50),
 *   finalTotal: new Decimal(59.50),
 *   isReceipt: true,
 *   taxIncludedInItems: false,
 *   tipAfterTax: false,
 *   deletedAt: null,
 *   lineItems: []
 * };
 * ```
 */
export interface Receipt {
  // Identifiers
  /** The unique identifier for this receipt */
  readonly id: number;

  /** The date and time when this receipt was created in the system */
  readonly createdAt: Date;

  /** The file path to the receipt image, or null if no image is available */
  readonly imagePath: string | null;

  /** The visibility setting for the receipt image: 'public' or 'owner_only' */
  readonly imageVisibility: 'public' | 'owner_only';

  /** The authentication user ID associated with this receipt, or null if not linked */
  readonly authUserId: string | null;

  // Core receipt data
  /** The name of the merchant or business where the receipt is from */
  readonly merchant: string | null;

  /** The date of the transaction, or null if not specified */
  readonly date: Date | null;

  /** The payment method used (e.g., "Credit Card", "Cash"), or null if not specified */
  readonly paymentMethod: string | null;

  // Amounts (all as Decimal for precision)
  /** The subtotal amount before taxes and fees, using Decimal.js for precision */
  readonly subtotal: Decimal | null;

  /** The display subtotal (may differ from subtotal for display purposes), using Decimal.js for precision */
  readonly displaySubtotal: Decimal | null;

  /** The tax amount, using Decimal.js for precision */
  readonly tax: Decimal | null;

  /** The tip amount, using Decimal.js for precision */
  readonly tip: Decimal | null;

  /** The original tip amount from the receipt image, using Decimal.js for precision */
  readonly originalTip: Decimal | null;

  /** The gratuity amount, using Decimal.js for precision */
  readonly gratuity: Decimal | null;

  /** The total amount, using Decimal.js for precision */
  readonly total: Decimal | null;

  /** The sum of all line item totals, using Decimal.js for precision */
  readonly itemsTotal: Decimal | null;

  /** The total before taxes, using Decimal.js for precision */
  readonly pretaxTotal: Decimal | null;

  /** The total after taxes but before tips/gratuity, using Decimal.js for precision */
  readonly posttaxTotal: Decimal | null;

  /** The final total including all charges, using Decimal.js for precision */
  readonly finalTotal: Decimal | null;

  // Flags
  /** Whether this record is confirmed to be a receipt (vs. a draft or other document type) */
  readonly isReceipt: boolean;

  /** Whether tax is already included in the individual line item prices */
  readonly taxIncludedInItems: boolean;

  /** Whether tip percentage buttons should calculate based on post-tax amount */
  readonly tipAfterTax: boolean;

  // Soft delete
  /** The date and time when this receipt was soft-deleted, or null if active */
  readonly deletedAt: Date | null;

  // Line items
  /** Array of line items that make up this receipt */
  readonly lineItems: readonly ReceiptLineItem[];
}

import Decimal from 'decimal.js';

import type {
  AssignmentWithReceiptUser,
  ReceiptWithLineItems,
} from '@/context/ReceiptContext';
import type { Assignment } from '@/models/Assignment';
import type { Receipt } from '@/models/Receipt';
import type { ReceiptLineItem } from '@/models/ReceiptLineItem';
import type { ReceiptUser } from '@/models/ReceiptUser';
import type { User } from '@/models/User';

/**
 * Transforms a Rocicorp Zero query result to the canonical Receipt interface.
 * Converts all numeric values to Decimal.js for precision and handles date conversions.
 * Zero stores dates as Unix timestamps (numbers), which are converted to Date objects.
 */
export function fromZeroReceipt(zeroReceipt: ReceiptWithLineItems): Receipt {
  console.log('='.repeat(100), 'fromZeroReceipt', zeroReceipt);
  // Convert Unix timestamps to Date objects
  const createdAt = new Date(zeroReceipt.created_at);
  const date = zeroReceipt.date ? new Date(zeroReceipt.date) : null;

  // Convert numeric fields to Decimal (null/undefined becomes null)
  const toDecimal = (value: number | null | undefined): Decimal | null =>
    value != null ? new Decimal(value) : null;

  // Transform line items
  const lineItems: readonly ReceiptLineItem[] = zeroReceipt.line_items.map(
    (item): ReceiptLineItem => ({
      id: item.id,
      name: item.name ?? null,
      quantity: new Decimal(item.quantity),
      pricePerItem: new Decimal(item.price_per_item),
      totalPrice: new Decimal(item.total_price),
      deletedAt: item.deleted_at ? new Date(item.deleted_at) : null,
      assignments: (item.assignments ?? []).map(
        (a: AssignmentWithReceiptUser): Assignment => ({
          id: a.id,
          receiptUserId: a.receipt_user_id,
          receiptLineItemId: a.receipt_line_item_id,
          createdAt: new Date(a.created_at),
          deletedAt: a.deleted_at ? new Date(a.deleted_at) : null,
          receiptUser: a.receipt_user
            ? {
                id: a.receipt_user.id,
                userId: a.receipt_user.user_id ?? null,
                displayName: a.receipt_user.display_name ?? null,
                createdAt: new Date(a.receipt_user.created_at),
                deletedAt: a.receipt_user.deleted_at
                  ? new Date(a.receipt_user.deleted_at)
                  : null,
                paidAt:
                  a.receipt_user.paid_at != null
                    ? new Date(a.receipt_user.paid_at)
                    : null,
                user: a.receipt_user.user
                  ? {
                      id: a.receipt_user.user.id,
                      authUserId: a.receipt_user.user.auth_user_id,
                      displayName: a.receipt_user.user.display_name ?? null,
                      createdAt: new Date(a.receipt_user.user.created_at),
                      deletedAt: a.receipt_user.user.deleted_at
                        ? new Date(a.receipt_user.user.deleted_at)
                        : null,
                    }
                  : null,
              }
            : null,
        })
      ),
    })
  );

  return {
    // Identifiers
    id: zeroReceipt.id,
    createdAt,
    imagePath: zeroReceipt.image_path ?? null,
    imageVisibility: (zeroReceipt.image_visibility ?? 'public') as
      | 'public'
      | 'owner_only',
    authUserId: zeroReceipt.user?.auth_user_id ?? null,

    // Core receipt data
    merchant: zeroReceipt.merchant ?? null,
    date,
    paymentMethod: zeroReceipt.payment_method ?? null,

    // Amounts (all as Decimal for precision)
    subtotal: toDecimal(zeroReceipt.subtotal),
    displaySubtotal: toDecimal(zeroReceipt.display_subtotal),
    tax: toDecimal(zeroReceipt.tax),
    tip: toDecimal(zeroReceipt.tip),
    originalTip: toDecimal(zeroReceipt.original_tip),
    gratuity: toDecimal(zeroReceipt.gratuity),
    total: toDecimal(zeroReceipt.total),
    itemsTotal: toDecimal(zeroReceipt.items_total),
    pretaxTotal: toDecimal(zeroReceipt.pretax_total),
    posttaxTotal: toDecimal(zeroReceipt.posttax_total),
    finalTotal: toDecimal(zeroReceipt.final_total),

    // Flags
    isReceipt: zeroReceipt.is_receipt ?? true,
    taxIncludedInItems: zeroReceipt.tax_included_in_items ?? false,
    tipAfterTax: zeroReceipt.tip_after_tax ?? false,

    // Soft delete
    deletedAt:
      zeroReceipt.deleted_at != null ? new Date(zeroReceipt.deleted_at) : null,

    // Line items
    lineItems,
  };
}

import { defineMutator, defineMutators } from '@rocicorp/zero';
import { z } from 'zod';

export const mutators = defineMutators({
  receipts: {
    update: defineMutator(
      z.object({
        id: z.number(),
        tip: z.number().optional(),
        gratuity: z.number().optional(),
        tip_after_tax: z.boolean().optional(),
        image_visibility: z.enum(['public', 'owner_only']).optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.user_receipts.update(args);
      }
    ),
    softDelete: defineMutator(
      z.object({ id: z.number() }),
      async ({ tx, args }) => {
        await tx.mutate.user_receipts.update({
          id: args.id,
          deleted_at: Date.now(),
        });
      }
    ),
  },
  lineItems: {
    update: defineMutator(
      z.object({
        id: z.string(),
        name: z.string().optional(),
        quantity: z.number().optional(),
        price_per_item: z.number().optional(),
        total_price: z.number().optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_line_items.update(args);
      }
    ),
    delete: defineMutator(
      z.object({
        id: z.string(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_line_items.delete({ id: args.id });
      }
    ),
    insert: defineMutator(
      z.object({
        id: z.string(),
        receipt_id: z.number(),
        name: z.string().optional(),
        quantity: z.number().optional(),
        price_per_item: z.number().optional(),
        total_price: z.number().optional(),
        created_at: z.number().optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_line_items.insert({
          id: args.id,
          receipt_id: args.receipt_id,
          name: args.name,
          quantity: args.quantity ?? 1,
          price_per_item: args.price_per_item ?? 0,
          total_price: args.total_price ?? 0,
          created_at: args.created_at ?? Date.now(),
        });
      }
    ),
  },
  receiptUsers: {
    insert: defineMutator(
      z.object({
        id: z.string(), // ULID
        display_name: z.string(),
        created_at: z.number().optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_users.insert({
          id: args.id,
          display_name: args.display_name,
          created_at: args.created_at ?? Date.now(),
        });
      }
    ),
    update: defineMutator(
      z.object({
        id: z.string(),
        user_id: z.number().nullish(), // null = unclaim, number = claim, undefined = no change
        display_name: z.string().optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_users.update(args);
      }
    ),
    updatePaidStatus: defineMutator(
      z.object({
        id: z.string(),
        paid_at: z.number().nullable(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.receipt_users.update({
          id: args.id,
          paid_at: args.paid_at,
        });
      }
    ),
    delete: defineMutator(
      z.object({ id: z.string() }), // ULID
      async ({ tx, args }) => {
        await tx.mutate.receipt_users.update({
          id: args.id,
          deleted_at: Date.now(),
        });
      }
    ),
  },
  assignments: {
    insert: defineMutator(
      z.object({
        id: z.string(), // ULID
        receipt_user_id: z.string(), // ULID
        receipt_line_item_id: z.string(),
        created_at: z.number().optional(),
      }),
      async ({ tx, args }) => {
        await tx.mutate.assignments.insert({
          id: args.id,
          receipt_user_id: args.receipt_user_id,
          receipt_line_item_id: args.receipt_line_item_id,
          created_at: args.created_at ?? Date.now(),
        });
      }
    ),
    delete: defineMutator(
      z.object({ id: z.string() }), // ULID
      async ({ tx, args }) => {
        await tx.mutate.assignments.update({
          id: args.id,
          deleted_at: Date.now(),
        });
      }
    ),
  },
});
